fun parseSourcesToFileScheme(content: String, mediaDir: String): String {
    val doc = Jsoup.parse(content)
    doc.outputSettings(OutputSettings().prettyPrint(false))

    // Collect all replacements to apply directly to the original string
    // This preserves the original content structure (including script tags)
    // Each entry: Pair(oldAttrValue, newUri)
    val replacements = mutableListOf<Pair<String, String>>()

    fun collectReplacements(tag: String, attr: String) {
        for (elem in doc.select(tag)) {
            val attrValue = elem.attr(attr)
            if (attrValue.isEmpty()) continue

            val attrUri = try {
                URI(attrValue)
            } catch (_: URISyntaxException) {
                continue
            }
            if (attrUri.scheme != null) continue

            val path = Paths.get(mediaDir, attrUri.path).toString()
            val newUri = getFileUri(path)

            replacements.add(Pair(attrValue, newUri.toString()))
        }
    }

    collectReplacements("img", "src")
    collectReplacements("video", "src")
    collectReplacements("audio", "src")
    collectReplacements("source", "src")
    collectReplacements("object", "data")

    if (replacements.isEmpty()) {
        return content
    }

    // Apply replacements directly to the original string to preserve structure
    // Use regex to handle various quoting styles (double-quoted, single-quoted, unquoted)
    // and always output with double quotes
    var result = content
    for ((oldValue, newValue) in replacements) {
        // Escape special regex characters in the old value
        val escapedOldValue = Regex.escape(oldValue)
        // Match attribute=value with optional quotes, case-insensitive for attribute name
        // Handles: attr="value", attr='value', attr=value (followed by space, >, newline, tab, etc.)
        val pattern = Regex(
            """(?i)((?:src|data)\s*=\s*)(?:"$escapedOldValue"|'$escapedOldValue'|$escapedOldValue(?=[\s>]))"""
        )
        result = pattern.replace(result) { matchResult ->
            "${matchResult.groupValues[1]}\"$newValue\""
        }
    }
